{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}{{ cours.titre|default('Détail du cours') }}{% endblock %}

{% block candidate_page_heading %}Détail du cours{% endblock %}

{% block candidate_breadcrumb %}
    / <a href="{{ path('app_candidate_cours') }}">Cours</a> / {{ cours.titre|default('Détail') }}
{% endblock %}

{% block candidate_content %}
    <div class="w-100 text-start fo-charte-ui">
        <a href="{{ path('app_candidate_cours') }}" class="btn btn-outline-secondary btn-sm mb-3">Retour aux cours</a>

        <div class="card shadow-sm fo-charte-card">
            {% if cours.imageCouverture %}
                <img src="{{ path('app_candidate_cours_image', {id: cours.id}) }}" class="card-img-top" alt="{{ cours.titre|default('Cours') }}" style="max-height: 300px; object-fit: cover;">
            {% endif %}

            <div class="card-body">
                <div class="d-flex justify-content-between align-items-start mb-3">
                    <h3 class="mb-0">{{ cours.titre|default('Cours') }}</h3>
                    <span class="badge badge-{{ cours.niveau == 'Débutant' ? 'success' : (cours.niveau == 'Intermédiaire' ? 'warning' : 'danger') }}">{{ cours.niveau|default('—') }}</span>
                </div>

                <p class="text-muted mb-3">
                    <strong>Durée:</strong> {{ cours.duree|default('—') }} h
                    &nbsp;|&nbsp;
                    <strong>Prix:</strong> {{ cours.prix is not null ? cours.prix ~ ' €' : 'Gratuit' }}
                </p>

                <h5>Description</h5>
                <p>{{ cours.description|default('Aucune description') }}</p>

                <h5>Compétences visées</h5>
                <p class="mb-0">{{ cours.competencesVisees|default('—') }}</p>

                <hr>
                <div class="d-flex justify-content-between align-items-center flex-wrap">
                    <div class="mb-2">
                        <strong>Progression :</strong> {{ progress|default(0) }}%
                    </div>
                    {% if continue_lesson is defined and continue_lesson %}
                        <a href="{{ path('app_candidate_lecon_show', {cours: cours.id, id: continue_lesson.id}) }}" class="btn btn-sm btn-primary mb-2">Continuer</a>
                    {% endif %}
                </div>
                <div class="progress mb-2" style="height: 10px;">
                    <div class="progress-bar bg-success" role="progressbar" style="width: {{ progress|default(0) }}%;" aria-valuenow="{{ progress|default(0) }}" aria-valuemin="0" aria-valuemax="100"></div>
                </div>
            </div>
        </div>

        <div class="card shadow-sm mt-4 fo-charte-card">
            <div class="card-header fo-charte-header">
                <h5 class="mb-0">Parcours du cours</h5>
            </div>
            <div class="card-body">
                {% if modules is empty %}
                    <p class="text-muted mb-0">Aucun module n'a encore été ajouté à ce cours.</p>
                {% else %}
                    <div id="course-accordion">
                        {% for module in modules %}
                            {% set module_lessons = lessons_by_module[module.id]|default([]) %}
                            <div class="card mb-2 fo-charte-card">
                                <div class="card-header bg-white" id="heading-{{ module.id }}">
                                    <button class="btn btn-link text-left p-0 w-100" data-toggle="collapse" data-target="#collapse-{{ module.id }}" aria-expanded="{{ loop.first ? 'true' : 'false' }}" aria-controls="collapse-{{ module.id }}">
                                        <span class="d-flex justify-content-between align-items-center">
                                            <span><strong>Module {{ module.ordre|default(loop.index) }}</strong> — {{ module.titre|default('Sans titre') }}</span>
                                            <span class="badge badge-light">{{ module_lessons|length }} leçon(s)</span>
                                        </span>
                                    </button>
                                </div>
                                <div id="collapse-{{ module.id }}" class="collapse {{ loop.first ? 'show' : '' }}" aria-labelledby="heading-{{ module.id }}" data-parent="#course-accordion">
                                    <div class="card-body">
                                        <p class="text-muted mb-3">{{ module.description|default('') }}</p>
                                        {% if module_lessons is empty %}
                                            <small class="text-muted">Aucune leçon pour ce module.</small>
                                        {% else %}
                                            <div class="list-group">
                                                {% for lesson in module_lessons %}
                                                    <a href="{{ path('app_candidate_lecon_show', {cours: cours.id, id: lesson.id}) }}" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
                                                        <span>
                                                            <strong>{{ lesson.titre|default('Leçon') }}</strong>
                                                        </span>
                                                        {% if viewed_lesson_ids[lesson.id]|default(false) %}
                                                            <span class="badge badge-success">Vue</span>
                                                        {% else %}
                                                            <span class="badge badge-light">Non vue</span>
                                                        {% endif %}
                                                    </a>
                                                {% endfor %}
                                            </div>
                                        {% endif %}
                                    </div>
                                </div>
                            </div>
                        {% endfor %}
                    </div>
                {% endif %}
            </div>
        </div>
    </div>
{% endblock %}

{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}Test final{% endblock %}

{% block candidate_page_heading %}Test final du cours{% endblock %}

{% block candidate_breadcrumb %}
    / <a href="{{ path('app_candidate_cours') }}">Cours</a>
    / <a href="{{ path('app_candidate_cours_show', {id: cours.id}) }}">{{ cours.titre|default('Cours') }}</a>
    / Test final
{% endblock %}

{% block candidate_content %}
    <div class="w-100 text-start fo-charte-ui">
        <a href="{{ path('app_candidate_cours_show', {id: cours.id}) }}" class="btn btn-outline-secondary btn-sm mb-3">Retour au cours</a>

        <div class="card shadow-sm fo-charte-card mb-4">
            <div class="card-body">
                <h4 class="mb-1">{{ cours.titre|default('Cours') }}</h4>
                <p class="text-muted mb-0">Test final de {{ expected_count }} questions - Seuil de réussite: {{ pass_threshold }}%</p>
            </div>
        </div>

        {% if latest_result %}
            <div class="alert {{ latest_result.reussite ? 'alert-success' : 'alert-warning' }} mb-4">
                Dernier résultat: {{ latest_result.score }}/{{ latest_result.totalPoints }}
                ({{ latest_result.totalPoints > 0 ? ((latest_result.score / latest_result.totalPoints) * 100)|round : 0 }}%)
                - {{ latest_result.reussite ? 'Réussi' : 'Non réussi' }}.
            </div>
        {% endif %}

        {% if questions is empty %}
            <div class="alert alert-light border">Aucune question de test final n'est disponible pour ce cours.</div>
        {% else %}
            <form method="post" class="card shadow-sm fo-charte-card" id="final-test-form">
                <div class="card-body">
                    {% for q in questions %}
                        <div class="mb-4 test-question-block {{ loop.first ? '' : 'd-none' }}" data-question-index="{{ loop.index0 }}">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h5 class="mb-0">{{ loop.index }}. {{ q.text }}</h5>
                                <span class="badge badge-success">{{ q.points }} pt{{ q.points > 1 ? 's' : '' }}</span>
                            </div>

                            {% for answer in q.answers %}
                                <div class="form-check mb-2">
                                    <input class="form-check-input" type="radio" name="answers[{{ q.id }}]" id="t{{ q.id }}_a{{ answer.id }}" value="{{ answer.id }}">
                                    <label class="form-check-label" for="t{{ q.id }}_a{{ answer.id }}">{{ answer.text }}</label>
                                </div>
                            {% endfor %}
                        </div>
                    {% endfor %}

                    <div class="d-flex justify-content-between align-items-center mt-3">
                        <button type="button" class="btn btn-outline-secondary" id="test-prev" disabled>Precedent</button>
                        <small class="text-muted" id="test-progress">Question 1/{{ questions|length }}</small>
                        <button type="button" class="btn btn-outline-primary" id="test-next">Suivant</button>
                    </div>

                    <hr>
                    <div class="text-end">
                        <button type="submit" class="btn btn-primary" id="test-submit">Terminer le test final</button>
                    </div>
                </div>
            </form>
        {% endif %}

        {% if result %}
            <div class="card shadow-sm fo-charte-card mt-4">
                <div class="card-body text-center">
                    <h4 class="mb-2">Score final: {{ result.score }}/{{ result.total_points }} ({{ result.percentage|round }}%)</h4>
                    <p class="mb-0 {{ result.passed ? 'text-success' : 'text-danger' }} font-weight-bold">
                        {{ result.passed ? 'Felicitations ! Test final reussi.' : 'Test final non reussi. Minimum ' ~ pass_threshold ~ '% requis.' }}
                    </p>
                </div>
            </div>
        {% endif %}
    </div>
{% endblock %}

{% block javascripts %}
    {{ parent() }}
    <script>
        document.addEventListener('DOMContentLoaded', function () {
            const blocks = Array.from(document.querySelectorAll('.test-question-block'));
            if (!blocks.length) {
                return;
            }

            let currentIndex = 0;
            const prevBtn = document.getElementById('test-prev');
            const nextBtn = document.getElementById('test-next');
            const progressLabel = document.getElementById('test-progress');
            const form = document.getElementById('final-test-form');

            const update = function () {
                blocks.forEach(function (block, index) {
                    block.classList.toggle('d-none', index !== currentIndex);
                });
                prevBtn.disabled = currentIndex === 0;
                nextBtn.disabled = currentIndex === (blocks.length - 1);
                progressLabel.textContent = 'Question ' + (currentIndex + 1) + '/' + blocks.length;
            };

            prevBtn?.addEventListener('click', function () {
                if (currentIndex > 0) {
                    currentIndex -= 1;
                    update();
                }
            });

            nextBtn?.addEventListener('click', function () {
                if (currentIndex < blocks.length - 1) {
                    currentIndex += 1;
                    update();
                }
            });

            form?.addEventListener('submit', function (event) {
                const totalQuestions = blocks.length;
                let answered = 0;

                blocks.forEach(function (block) {
                    if (block.querySelector('input[type="radio"]:checked')) {
                        answered += 1;
                    }
                });

                if (answered < totalQuestions) {
                    event.preventDefault();
                    alert('Veuillez repondre a toutes les questions avant de terminer.');
                }
            });

            update();
        });
    </script>
{% endblock %}

