                        {{ result.passed ? 'Felicitations ! Quiz reussi.' : 'Quiz non reussi. Minimum ' ~ pass_threshold ~ '% requis.' }}
                    </p>
                </div>
            </div>
        {% endif %}
    </div>
{% endblock %}

